const categories = ($.input.categories || 'cybersecurity, data privacy, compliance, vulnerabilities').split(',').map(c => c.trim()).filter(Boolean);
const focus = $.input.focusKeywords || '';
const queries = categories.map(cat => {
  let q = 'latest ' + cat + ' news and advisories';
  if (focus) q += ' ' + focus;
  return { category: cat, query: q };
});
return { queries, categoryCount: queries.length };

const queries = $.steps.buildQueries.output.queries;
const iterations = $.steps.searchCategories.response.iterations || [];
let compiled = '';
let totalArticles = 0;

queries.forEach((q, i) => {
  const iter = iterations[i];
  const results = (iter && iter.searchCategory && iter.searchCategory.response && iter.searchCategory.response.results) ? iter.searchCategory.response.results : [];
  compiled += '=== CATEGORY: ' + q.category.toUpperCase() + ' ===\n';
  results.forEach((r, j) => {
    compiled += (j + 1) + '. ' + (r.title || 'Untitled') + '\n';
    compiled += '   URL: ' + (r.url || '') + '\n';
    compiled += '   ' + (r.text || '').slice(0, 1000) + '\n\n';
    totalArticles++;
  });
});

return { compiled: compiled.slice(0, 30000), totalArticles };

const d = $.steps.compileArticles.output;
const categories = $.input.categories || 'cybersecurity, data privacy, compliance, vulnerabilities';
const focus = $.input.focusKeywords || '';
const today = new Date().toISOString().slice(0, 10);

let prompt = 'You are a cybersecurity analyst creating a daily intelligence digest for security, privacy, and compliance professionals.\n\n';
prompt += 'DATE: ' + today + '\n';
prompt += 'CATEGORIES: ' + categories + '\n';
if (focus) prompt += 'PRIORITY KEYWORDS: ' + focus + '\n';
prompt += 'TOTAL ARTICLES: ' + d.totalArticles + '\n\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Categorize each article by security domain\n';
prompt += '- Rate severity/importance: critical, high, medium, low\n';
prompt += '- Summarize each article in 2-3 sentences\n';
prompt += '- Identify actionable items that require immediate attention\n';
prompt += '- Group related articles and highlight emerging threats\n';
prompt += '- Create an executive summary suitable for a CISO briefing\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "executiveSummary": "3-4 sentence CISO-level overview",\n';
prompt += '  "articles": [\n';
prompt += '    {\n';
prompt += '      "title": "article title",\n';
prompt += '      "url": "url",\n';
prompt += '      "category": "cybersecurity|privacy|compliance|vulnerability",\n';
prompt += '      "severity": "critical|high|medium|low",\n';
prompt += '      "summary": "2-3 sentence summary",\n';
prompt += '      "actionRequired": "what to do, if anything"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "criticalAlerts": ["items requiring immediate attention"],\n';
prompt += '  "emergingThreats": ["newly identified threat patterns"],\n';
prompt += '  "complianceUpdates": ["regulatory or compliance news"],\n';
prompt += '  "recommendedActions": ["top actions for the security team"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { executiveSummary: raw, articles: [], criticalAlerts: [], emergingThreats: [], complianceUpdates: [], recommendedActions: [] }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);

let body = 'SECURITY & COMPLIANCE DAILY DIGEST - ' + today + '\n\n';
body += 'EXECUTIVE SUMMARY\n';
body += (ai.executiveSummary || 'No summary available') + '\n\n';

if (ai.criticalAlerts && ai.criticalAlerts.length > 0) {
  body += 'CRITICAL ALERTS\n';
  ai.criticalAlerts.forEach((a, i) => { body += '  [!] ' + a + '\n'; });
  body += '\n';
}

body += 'ARTICLES (' + (ai.articles || []).length + ')\n';
body += '-'.repeat(40) + '\n';
(ai.articles || []).forEach((a, i) => {
  const severityTag = a.severity === 'critical' ? '[CRITICAL]' : a.severity === 'high' ? '[HIGH]' : a.severity === 'medium' ? '[MEDIUM]' : '[LOW]';
  body += (i + 1) + '. ' + severityTag + ' ' + (a.title || '') + '\n';
  body += '   Category: ' + (a.category || '') + '\n';
  body += '   ' + (a.summary || '') + '\n';
  if (a.url) body += '   Link: ' + a.url + '\n';
  if (a.actionRequired) body += '   Action: ' + a.actionRequired + '\n';
  body += '\n';
});

if (ai.emergingThreats && ai.emergingThreats.length > 0) {
  body += 'EMERGING THREATS\n';
  ai.emergingThreats.forEach((t, i) => { body += '  ' + (i + 1) + '. ' + t + '\n'; });
  body += '\n';
}

if (ai.recommendedActions && ai.recommendedActions.length > 0) {
  body += 'RECOMMENDED ACTIONS\n';
  ai.recommendedActions.forEach((a, i) => { body += '  ' + (i + 1) + '. ' + a + '\n'; });
}

body += '\n---\nGenerated by One CLI + Claude AI';

const criticalCount = (ai.articles || []).filter(a => a.severity === 'critical' || a.severity === 'high').length;
const subject = 'Security Digest ' + today + (criticalCount > 0 ? ' [' + criticalCount + ' HIGH/CRITICAL]' : '');
return { body, subject };

const ai = $.steps.parseAI.output;
const articles = ai.articles || [];
const critical = articles.filter(a => a.severity === 'critical');
const high = articles.filter(a => a.severity === 'high');

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Security & Compliance Digest', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Articles:* ' + articles.length + ' | :red_circle: Critical: ' + critical.length + ' | :large_yellow_circle: High: ' + high.length } });
blocks.push({ type: 'divider' });

if (ai.executiveSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary:* ' + ai.executiveSummary.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

if (ai.criticalAlerts && ai.criticalAlerts.length > 0) {
  let alertText = ':rotating_light: *Critical Alerts:*\n';
  ai.criticalAlerts.forEach((a, i) => { alertText += (i + 1) + '. ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: alertText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

critical.concat(high).slice(0, 5).forEach(a => {
  const icon = a.severity === 'critical' ? ':red_circle:' : ':large_yellow_circle:';
  let text = icon + ' *' + (a.title || 'Untitled') + '* [' + a.category + ']\n';
  text += (a.summary || '').slice(0, 300) + '\n';
  if (a.url) text += '<' + a.url + '|Read more>';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

if (ai.recommendedActions && ai.recommendedActions.length > 0) {
  blocks.push({ type: 'divider' });
  let actText = '*Recommended Actions:*\n';
  ai.recommendedActions.slice(0, 5).forEach((a, i) => { actText += (i + 1) + '. ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: actText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Full digest emailed to ' + $.input.emailRecipient + ' | One CLI' }] });
const fallback = 'Security Digest: ' + articles.length + ' articles, ' + critical.length + ' critical';
return { blocks, fallback };
